import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import { VirtualizedList } from './VirtualizedList';

const makeItems = (n: number) =>
  Array.from({ length: n }, (_, i) => ({ id: i, label: `Item ${i}` }));

describe('VirtualizedList', () => {
  it('does not render all items in the DOM', () => {
    const items = makeItems(1000);
    render(
      <VirtualizedList
        items={items}
        height={200}
        rowHeight={40}
        renderItem={(item) => <span>{(item as any).label}</span>}
      />
    );
    const rendered = screen.getAllByTestId(/^vlist-row-/);
    expect(rendered.length).toBeLessThan(100);
  });

  it('renders rows near the top initially', () => {
    const items = makeItems(100);
    render(
      <VirtualizedList
        items={items}
        height={200}
        rowHeight={40}
        renderItem={(item) => <span>{(item as any).label}</span>}
      />
    );
    expect(screen.getByTestId('vlist-row-0')).toBeInTheDocument();
    expect(screen.getByTestId('vlist-row-4')).toBeInTheDocument();
  });

  it('sets correct total height on the spacer', () => {
    const items = makeItems(500);
    render(
      <VirtualizedList
        items={items}
        height={200}
        rowHeight={40}
        renderItem={(item) => <span>{(item as any).label}</span>}
      />
    );
    const spacer = screen.getByTestId('vlist-spacer');
    expect(spacer.style.height).toBe('20000px');
  });

  it('displays item count', () => {
    const items = makeItems(500);
    render(
      <VirtualizedList
        items={items}
        height={200}
        rowHeight={40}
        renderItem={(item) => <span>{(item as any).label}</span>}
      />
    );
    const countEl = screen.getByTestId('vlist-count');
    expect(countEl).toHaveTextContent('500');
  });

  it('positions rows with translateY', () => {
    const items = makeItems(100);
    render(
      <VirtualizedList
        items={items}
        height={200}
        rowHeight={40}
        renderItem={(item) => <span>{(item as any).label}</span>}
      />
    );
    const row2 = screen.getByTestId('vlist-row-2');
    expect(row2.style.transform).toContain('translateY');
  });
});

