import React, { useState, useCallback, useMemo } from 'react';
import './styles.css';

interface VirtualizedListProps<T> {
  items: T[];
  height?: number;
  rowHeight?: number;
  renderItem: (item: T, index: number) => React.ReactNode;
}

const OVERSCAN = 2;

export function VirtualizedList<T>({
  items,
  height = 400,
  rowHeight = 40,
  renderItem,
}: VirtualizedListProps<T>) {
  const [scrollTop, setScrollTop] = useState(0);

  const totalHeight = items.length * rowHeight;
  const visibleCount = Math.ceil(height / rowHeight);
  const startIdx = Math.max(0, Math.floor(scrollTop / rowHeight) - OVERSCAN);
  const endIdx = Math.min(items.length, startIdx + visibleCount + 2 * OVERSCAN);

  const visibleItems = useMemo(
    () => items.slice(startIdx, endIdx).map((item, i) => ({ item, index: startIdx + i })),
    [items, startIdx, endIdx],
  );

  const handleScroll = useCallback((e: React.UIEvent<HTMLDivElement>) => {
    setScrollTop((e.target as HTMLDivElement).scrollTop);
  }, []);

  return (
    <div>
      <div data-testid="vlist-count" className="vl__count">
        Showing {visibleItems.length} of {items.length} items
      </div>
      <div
        data-testid="vlist-container"
        className="vl__container"
        style={{ height }}
        onScroll={handleScroll}
      >
        <div
          data-testid="vlist-spacer"
          className="vl__spacer"
          style={{ height: totalHeight }}
        >
          {visibleItems.map(({ item, index }) => (
            <div
              key={index}
              data-testid={`vlist-row-${index}`}
              className="vl__row"
              style={{
                height: rowHeight,
                transform: `translateY(${index * rowHeight}px)`,
              }}
            >
              {renderItem(item, index)}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default VirtualizedList;
